create table dirkspzm32.s_erp_rcv_pack_vorschr (
    sid                  varchar2(2 char) not null enable,
    firma_nr             number(3, 0) not null enable,
    artikel              varchar2(30 char) not null enable,
    kunden_nr            varchar2(10 char) not null enable,
    lhm_art_1            varchar2(20 char),
    lhm_art_2            varchar2(20 char),
    lhm_art_3            varchar2(20 char),
    lhm_art_4            varchar2(20 char),
    lhm_art_5            varchar2(20 char),
    top_art              varchar2(20 char),
    pal_art              varchar2(20 char),
    sep_art              varchar2(20 char),
    sep_anz              number(*, 5),
    box_art              varchar2(20 char),
    box_anz              varchar2(20 char),
    folie                varchar2(1 char),
    um_band              varchar2(1 char),
    ausg_ende            varchar2(50 char),
    komm_art             varchar2(50 char),
    waage_hin            varchar2(50 char),
    pack_schema          varchar2(8 char),
    lhm_eti_1            varchar2(20 char),
    lhm_eti_2            varchar2(20 char),
    lhm_eti_3            varchar2(20 char),
    lhm_eti_4            varchar2(20 char),
    lhm_eti_5            varchar2(20 char),
    lhm_eti_6            varchar2(20 char),
    lte_eti_1            varchar2(20 char),
    lte_eti_2            varchar2(20 char),
    lte_eti_3            varchar2(20 char),
    lte_eti_4            varchar2(20 char),
    lte_eti_5            varchar2(20 char),
    lte_eti_6            varchar2(20 char),
    created_date         date not null enable,
    created_login_id     number(*, 0),
    last_change_date     date,
    last_change_login_id number(*, 0),
    b_datum              varchar2(19 char),
    ts                   date,
    tsc                  date
);

alter table dirkspzm32.s_erp_rcv_pack_vorschr
    add constraint pk_s_erp_rcv_pack_vorschr
        primary key ( artikel,
                      kunden_nr,
                      firma_nr,
                      sid )
            using index enable;


